import { useRef } from 'react';
import { useScroll, useTransform, motion } from 'framer-motion';

interface AnimatedTextProps {
  text: string;
  className?: string;
}

export function AnimatedText({ text, className }: AnimatedTextProps) {
  const ref = useRef<HTMLParagraphElement>(null);
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ['start 0.8', 'end 0.2'],  // começa quando 80% visível, termina a 20%
  });

  const words = text.split(' ');

  return (
    <p ref={ref} className={className} style={{ position: 'relative' }}>
      {words.map((word, wordIndex) => {
        const chars = word.split('');
        const wordStart = wordIndex / words.length;
        const wordEnd = (wordIndex + 1) / words.length;

        return (
          <span key={wordIndex} style={{ display: 'inline-block', marginRight: '0.3em' }}>
            {chars.map((char, charIndex) => {
              const charStart = wordStart + (charIndex / chars.length) * (wordEnd - wordStart);
              const charEnd = wordStart + ((charIndex + 1) / chars.length) * (wordEnd - wordStart);

              // eslint-disable-next-line react-hooks/rules-of-hooks
              const opacity = useTransform(
                scrollYProgress,
                [charStart, charEnd],
                [0.2, 1]
              );

              return (
                <motion.span
                  key={charIndex}
                  style={{ opacity, display: 'inline-block' }}
                >
                  {char}
                </motion.span>
              );
            })}
          </span>
        );
      })}
    </p>
  );
}
